```class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        def lcs(s1, s2):
            m, n = len(s1), len(s2)
            dp = [[0] * (n + 1) for _ in range(m + 1)]
            for i in range(1, m + 1):
                for j in range(1, n + 1):
                    if s1[i - 1] == s2[j - 1]:
                        dp[i][j] = dp[i - 1][j - 1] + 1
                    else:
                        dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])
            return dp[m][n]

        lcs_s1_s2 = lcs(s1, s2)
        lcs_s1_s3 = lcs(s1, s3)
        lcs_s2_s3 = lcs(s2, s3)
        if lcs_s1_s2 + lcs_s1_s3 + lcs_s2_s3 == min(len(s1), len(s2), len(s3)):
            return len(s1) + len(s2) + len(s3) - 2 * lcs_s1_s2 - 2 * lcs_s1_s3 - 2 * lcs_s2_s3
        else:
            return -1
